  _qu2('upper','suffix',4,2,'grammar','Which is the correct adjective form of "envy"?',['envious','envyous','envieous','envioues'],'envious',term:2),

  // Set 3 — comprehension
  _qu2('upper','suffix',4,3,'comprehension','PASSAGE: The suffix "-ous" (and its variants "-ious" and "-eous") turns nouns into adjectives meaning "full of" or "having the quality of". The base word sometimes changes: "glory" drops the y and adds -ious to form "glorious"; "advantage" keeps its e to form "advantageous"; "mystery" drops y for i to give "mysterious". Some words keep their base form almost intact — "famous" from "fame", and "dangerous" from "danger". Knowing these patterns helps you read and spell a huge range of English adjectives accurately.\n\nQ: What does the suffix "-ous" turn nouns into?',['Adjectives meaning "full of" or "having the quality of"','Verbs meaning "to do with"','Adverbs meaning "in a way that"','Nouns meaning "the state of"'],'Adjectives meaning "full of" or "having the quality of"',term:2),
  _qu2('upper','suffix',4,3,'comprehension','Refer to the passage above (-ous suffix).\n\nQ: How is "glorious" formed from "glory"?',['The y is dropped and -ious is added','The y is kept and -ous is added','An e is added before -ious','The word is entirely rewritten'],'The y is dropped and -ious is added',term:2),
  _qu2('upper','suffix',4,3,'comprehension','Refer to the passage above (-ous suffix).\n\nQ: Why is it "advantageous" and not "advantagous"?',['The e is kept before "-ous" in this pattern','The e is always dropped','An i is added before -ous','Nothing changes in advantage'],'The e is kept before "-ous" in this pattern',term:2),
  _qu2('upper','suffix',4,3,'comprehension','Refer to the passage above (-ous suffix).\n\nQ: What does "dangerous" come from?',['"danger" with "-ous" added','"dangerious" shortened','A completely different root','Dropping y from "dangery"'],'"danger" with "-ous" added',term:2),
  _qu2('upper','suffix',4,3,'comprehension','Refer to the passage above (-ous suffix).\n\nQ: What is the benefit of knowing the -ous suffix patterns?',['It helps you read and spell a wide range of adjectives accurately','It helps you build verbs from nouns','It helps you write full sentences','It helps you understand Greek roots'],'It helps you read and spell a wide range of adjectives accurately',term:2),
  _qu2('upper','suffix',4,3,'grammar','Which is the correct adjective form of "humour"?',['humorous','humourios','humoureous','humouros'],'humorous',term:2),
  _qu2('upper','suffix',4,3,'grammar','Which is the correct adjective form of "nerve"?',['nervous','nerveous','nerveious','nervious'],'nervous',term:2),
  _qu2('upper','suffix',4,3,'vocabulary','What does "prosperous" mean?',['successful and wealthy','full of mystery','very dangerous','full of victory'],'successful and wealthy',term:2),
  _qu2('upper','suffix',4,3,'vocabulary','What does "harmonious" mean?',['peaceful and in agreement','full of danger','very ambitious','extremely outrageous'],'peaceful and in agreement',term:2),
  _qu2('upper','suffix',4,3,'grammar','Which sentence uses "-ious" correctly?',['She gave a victorious speech after winning the trophy.','She gave a victoryous speech after winning.','She gave a victorioues speech after winning.','She gave a victorieous speech after winning.'],'She gave a victorious speech after winning the trophy.',term:2),

