  // Set 3 — comprehension
  _qu2('upper','suffix',5,3,'comprehension','PASSAGE: In a recent speech, the school head spoke about academic achievement. "Your improvement this term has been remarkable," she told students. "The difference between those who succeed and those who struggle is not intelligence — it is persistence." She praised students for their obedience and reliance on one another during group projects. "Government exists to serve the people," she added, "and your existence in this school community carries significance. Every action has a consequence."\n\nQ: What does the school head say is the difference between students who succeed and those who struggle?',['Persistence, not intelligence','Intelligence, not persistence','Achievement, not obedience','Performance, not existence'],'Persistence, not intelligence',term:2),
  _qu2('upper','suffix',5,3,'comprehension','Refer to the passage above (school head\'s speech).\n\nQ: What does "significance" mean as used in the passage?',['The quality of being important or meaningful','The act of performing in class','The state of relying on others','The quality of being obedient'],'The quality of being important or meaningful',term:2),
  _qu2('upper','suffix',5,3,'comprehension','Refer to the passage above (school head\'s speech).\n\nQ: Which word is the noun form of "achieve"?',['achievement','persistence','significance','obedience'],'achievement',term:2),
  _qu2('upper','suffix',5,3,'comprehension','Refer to the passage above (school head\'s speech).\n\nQ: What does "persistence" mean?',['continuing firmly despite difficulties','the act of achieving','the state of obedience','the quality of relying on others'],'continuing firmly despite difficulties',term:2),
  _qu2('upper','suffix',5,3,'comprehension','Refer to the passage above (school head\'s speech).\n\nQ: What suffix makes "exist" into "existence"?',['-ence','-ment','-ance','-ious'],'-ence',term:2),
  _qu2('upper','suffix',5,3,'grammar','Which is correct: "attend" → noun?',['attendance','attendment','attendence','attendans'],'attendance',term:2),
  _qu2('upper','suffix',5,3,'grammar','Which is correct: "judge" → noun?',['judgement','judgeance','judgeence','judgeious'],'judgement',term:2),
  _qu2('upper','suffix',5,3,'vocabulary','What does "persistence" mean?',['continuing firmly despite difficulties','the act of moving','the state of existing','the quality of achieving'],'continuing firmly despite difficulties',term:2),
  _qu2('upper','suffix',5,3,'vocabulary','What does "consequence" mean?',['a result or effect of an action','a type of performance','a noun suffix','a state of obedience'],'a result or effect of an action',term:2),
  _qu2('upper','suffix',5,3,'grammar','Which sentence uses "-ance" correctly?',['His attendance at every class impressed his teacher.','His attendment at every class impressed his teacher.','His attendence at every class impressed his teacher.','His attendious at every class impressed his teacher.'],'His attendance at every class impressed his teacher.',term:2),

