  // Set 1
  _qu2('upper','prefix',6,1,'vocabulary','Which word is most persuasive: "This is a ___ issue that must be addressed."',['critical','okay','fine','small'],'critical',term:2),
  _qu2('upper','prefix',6,1,'vocabulary','What does "essential" mean?',['absolutely necessary','very large','slightly useful','not important'],'absolutely necessary',term:2),
  _qu2('upper','prefix',6,1,'vocabulary','What does "vital" mean?',['extremely important; necessary for success','quite useful sometimes','not very significant','optional and minor'],'extremely important; necessary for success',term:2),
  _qu2('upper','prefix',6,1,'vocabulary','What does "significant" mean?',['important; large enough to be noticed','very small','slightly different','completely ordinary'],'important; large enough to be noticed',term:2),
  _qu2('upper','prefix',6,1,'grammar','Which sentence uses persuasive language most effectively?',['Every student deserves access to quality education — it is a fundamental right.','Students should maybe get a chance to learn if possible.','Education might be kind of important in some situations.','I think school is okay and probably should continue.'],'Every student deserves access to quality education — it is a fundamental right.',term:2),
  _qu2('upper','prefix',6,1,'grammar','Which technique is used in: "If we do nothing, future generations will suffer."',['Appeal to consequences','A list of facts','A personal anecdote','A definition'],'Appeal to consequences',term:2),
  _qu2('upper','prefix',6,1,'grammar','Which technique is used in: "Scientists, doctors, and teachers all agree on this."',['Appeal to authority / rule of three','A metaphor','A simile','A rhetorical question'],'Appeal to authority / rule of three',term:2),
  _qu2('upper','prefix',6,1,'grammar','Which technique is used in: "Can we really afford to ignore this?"',['Rhetorical question','Simile','Factual statement','Metaphor'],'Rhetorical question',term:2),
  _qu2('upper','prefix',6,1,'vocabulary','What does "inevitable" mean?',['certain to happen; unavoidable','possibly might happen','not likely to happen','completely avoidable'],'certain to happen; unavoidable',term:2),
