  // Set 1
  _qu2('upper','alternative_spelling',7,1,'grammar','Which sentence is written in formal English?',['The research indicates a significant correlation between nutrition and academic performance.','The research shows that eating well helps students do better in school.','Eating well is super important for doing great in school.','Loads of research says healthy food makes you smarter.'],'The research indicates a significant correlation between nutrition and academic performance.',term:2),
  _qu2('upper','alternative_spelling',7,1,'grammar','Which sentence is written in informal English?',['I reckon we should try a different approach to the problem.','The evidence suggests an alternative approach is warranted.','A thorough investigation of the issue is required.','The committee will deliberate on the matter.'],'I reckon we should try a different approach to the problem.',term:2),
  _qu2('upper','alternative_spelling',7,1,'vocabulary','What is the formal equivalent of "get better"?',['improve','get nicer','become more okay','do not be worse'],'improve',term:2),
  _qu2('upper','alternative_spelling',7,1,'vocabulary','What is the formal equivalent of "a lot of"?',['numerous','loads of','tons of','heaps of'],'numerous',term:2),
  _qu2('upper','alternative_spelling',7,1,'vocabulary','What is the formal equivalent of "show"?',['demonstrate','prove it clearly','point something out','kind of show'],'demonstrate',term:2),
  _qu2('upper','alternative_spelling',7,1,'grammar','Which word should be replaced to make this more formal: "The study was done by scientists who found out a lot."',['"done" → "conducted" and "a lot" → "numerous findings"','Keep it exactly as it is','Replace "scientists" with "researchers" only','Remove "a lot" only'],'"done" → "conducted" and "a lot" → "numerous findings"',term:2),
  _qu2('upper','alternative_spelling',7,1,'vocabulary','What is the formal equivalent of "find out"?',['investigate','check on something','look around for','try to see'],'investigate',term:2),
  _qu2('upper','alternative_spelling',7,1,'grammar','Which sentence uses appropriately formal academic language?',['The findings of the study suggest that early intervention is highly beneficial.','The study basically shows that doing stuff early is really helpful.','Basically what the study says is starting early works well.','The study says starting early is super helpful for sure.'],'The findings of the study suggest that early intervention is highly beneficial.',term:2),
  _qu2('upper','alternative_spelling',7,1,'vocabulary','What is the formal equivalent of "big"?',['substantial','really big','super large','very very big'],'substantial',term:2),
  _qu2('upper','alternative_spelling',7,1,'vocabulary','What is the formal equivalent of "use"?',['utilise','make use of in a way','do something with','handle a thing'],'utilise',term:2),

  // Set 2
  _qu2('upper','alternative_spelling',7,2,'grammar','Rewrite in formal English: "The school needs to fix stuff."',['The school must address several outstanding issues.','The school needs to improve things considerably.','The school gotta fix what\'s broken.','The school should kind of update its stuff.'],'The school must address several outstanding issues.',term:2),
  _qu2('upper','alternative_spelling',7,2,'grammar','Rewrite in formal English: "She\'s really good at science."',['She demonstrates exceptional ability in the field of science.','She is very good at doing science stuff.','Science is something she can do really well.','She does science in a very good way.'],'She demonstrates exceptional ability in the field of science.',term:2),
  _qu2('upper','alternative_spelling',7,2,'vocabulary','What is the formal equivalent of "okay"?',['satisfactory','kind of fine','not bad enough','good enough maybe'],'satisfactory',term:2),
  _qu2('upper','alternative_spelling',7,2,'vocabulary','What is the formal equivalent of "start"?',['commence','begin doing','start to do','kick off'],'commence',term:2),
  _qu2('upper','alternative_spelling',7,2,'grammar','Which feature is typical of informal writing?',['Contractions such as "don\'t" and "I\'m"','Passive voice constructions','Subject-verb agreement','Academic vocabulary'],'Contractions such as "don\'t" and "I\'m"',term:2),
  _qu2('upper','alternative_spelling',7,2,'grammar','Which feature is typical of formal writing?',['Passive voice: "It was observed that..."','Contractions: "It\'s been shown..."','Slang: "This is super important"','Direct address: "You really need to..."'],'Passive voice: "It was observed that..."',term:2),
  _qu2('upper','alternative_spelling',7,2,'vocabulary','What is the formal equivalent of "try"?',['endeavour','have a go at','give it a shot','maybe try to do it'],'endeavour',term:2),
  _qu2('upper','alternative_spelling',7,2,'vocabulary','What is the formal equivalent of "enough"?',['sufficient','kind of enough','plenty enough','loads'],'sufficient',term:2),
  _qu2('upper','alternative_spelling',7,2,'grammar','Which sentence uses passive voice in formal writing?',['It was concluded that further research is required.','We concluded we need more research.','Researchers said we need more research.','I think we should do more research.'],'It was concluded that further research is required.',term:2),
  _qu2('upper','alternative_spelling',7,2,'vocabulary','What is the formal equivalent of "think"?',['consider','guess','reckon','kind of feel'],'consider',term:2),

  // Set 3 — comprehension
  _qu2('upper','alternative_spelling',7,3,'comprehension','PASSAGE: Language register refers to the style and formality of language used in a particular context. Formal language is used in academic writing, official letters, and professional communication. It avoids contractions, uses precise vocabulary, and often employs passive voice constructions. Informal language is used among friends, in casual conversation, and in personal messages. It may include slang, contractions, and colloquial expressions. Skilled writers can switch between registers depending on their audience and purpose — a skill known as "code-switching".\n\nQ: Where is formal language typically used?',['Academic writing, official letters, and professional communication','Among friends and in casual conversation','In personal messages and text messages','In slang and colloquial expressions'],'Academic writing, official letters, and professional communication',term:2),
  _qu2('upper','alternative_spelling',7,3,'comprehension','Refer to the passage above (language register).\n\nQ: What does formal language avoid, according to the passage?',['Contractions such as "don\'t"','Precise vocabulary','Passive voice constructions','Long sentences'],'Contractions such as "don\'t"',term:2),
  _qu2('upper','alternative_spelling',7,3,'comprehension','Refer to the passage above (language register).\n\nQ: What is "code-switching"?',['The ability to switch between formal and informal registers','Writing in a foreign language','A type of passive voice construction','The use of slang in academic writing'],'The ability to switch between formal and informal registers',term:2),
  _qu2('upper','alternative_spelling',7,3,'comprehension','Refer to the passage above (language register).\n\nQ: What does "colloquial" mean in the passage?',['Everyday, conversational expressions','Very formal vocabulary','Passive constructions','Precise academic language'],'Everyday, conversational expressions',term:2),
  _qu2('upper','alternative_spelling',7,3,'comprehension','Refer to the passage above (language register).\n\nQ: What determines which register a skilled writer uses?',['Their audience and purpose','Their personal preference only','The length of the piece','The topic alone'],'Their audience and purpose',term:2),
  _qu2('upper','alternative_spelling',7,3,'grammar','Which sentence is from a formal letter?',['I am writing to formally request a copy of the examination results.','Hey, can you send me my exam results?','I just need my results, thanks.','Could you maybe send the results when possible?'],'I am writing to formally request a copy of the examination results.',term:2),
  _qu2('upper','alternative_spelling',7,3,'vocabulary','What does "colloquial" mean?',['typical of informal, everyday conversation','typical of academic writing','typical of formal letters','typical of passive constructions'],'typical of informal, everyday conversation',term:2),
  _qu2('upper','alternative_spelling',7,3,'vocabulary','What does "register" mean in language?',['the level of formality or style used in a particular context','a list of students in a class','a device for recording speech','a formal document'],'the level of formality or style used in a particular context',term:2),
  _qu2('upper','alternative_spelling',7,3,'grammar','Which rewrite is most formal?',['The committee has decided to postpone the meeting.','The committee said they\'ll push the meeting back.','The meeting\'s been pushed back by the committee.','The committee is gonna delay the meeting.'],'The committee has decided to postpone the meeting.',term:2),
  _qu2('upper','alternative_spelling',7,3,'vocabulary','What does "precise" mean?',['exact and accurate','very informal','quite colloquial','slightly vague'],'exact and accurate',term:2),

