  // Set 1
  _qu2('upper','suffix',9,1,'grammar','What is the purpose of a topic sentence?',['It introduces the main idea of a paragraph','It concludes the paragraph','It provides examples','It defines vocabulary'],'It introduces the main idea of a paragraph',term:2),
  _qu2('upper','suffix',9,1,'grammar','What is the purpose of a subheading in a report?',['It organises the report into clear sections and helps readers navigate it','It provides evidence for the main argument','It introduces personal opinions','It concludes each paragraph'],'It organises the report into clear sections and helps readers navigate it',term:2),
  _qu2('upper','suffix',9,1,'grammar','Which sentence is a strong topic sentence for a paragraph about Nigeria\'s economy?',['Nigeria\'s economy is the largest in Africa, driven primarily by oil production and a growing services sector.','This paragraph is about Nigeria\'s economy.','Nigeria has many things including oil and services.','The economy is important and Nigeria has one.'],'Nigeria\'s economy is the largest in Africa, driven primarily by oil production and a growing services sector.',term:2),
  _qu2('upper','suffix',9,1,'vocabulary','What does "domain-specific" vocabulary mean?',['Words related to a particular subject or field','Very long and complex words','Words from Latin and Greek only','Words that appear in formal letters'],'Words related to a particular subject or field',term:2),
  _qu2('upper','prefix',9,1,'vocabulary','Which is an example of domain-specific vocabulary in science?',['photosynthesis','beautiful','because','although'],'photosynthesis',term:2),
  _qu2('upper','suffix',9,1,'grammar','In a 3-paragraph report, what should the first paragraph introduce?',['The topic and its significance / background','The conclusion and recommendations','All supporting evidence','A vocabulary list'],'The topic and its significance / background',term:2),
  _qu2('upper','suffix',9,1,'grammar','Which transition phrase best introduces evidence in a report?',['According to research,...','I think that...','It might be true that...','You should know that...'],'According to research,...',term:2),
  _qu2('upper','suffix',9,1,'grammar','Which sentence best concludes a report paragraph?',['It is therefore evident that access to education is fundamental to national development.','Education is nice and everyone agrees it is good.','So basically education is important for the country.','Education — which is very good — matters a lot.'],'It is therefore evident that access to education is fundamental to national development.',term:2),
  _qu2('upper','prefix',9,1,'vocabulary','Which is domain-specific vocabulary for geography?',['topography','because','quickly','magnificent'],'topography',term:2),
  _qu2('upper','suffix',9,1,'grammar','What should be avoided in a formal report?',['Personal pronouns like "I think" and "I believe"','Topic sentences','Subheadings','Domain-specific vocabulary'],'Personal pronouns like "I think" and "I believe"',term:2),

  // Set 2
  _qu2('upper','suffix',9,2,'grammar','Which subheading is most appropriate for a report about climate change?',['Causes of Climate Change','My Thoughts on Climate Change','Why Climate Change Is Bad','Stuff About Climate Change'],'Causes of Climate Change',term:2),
  _qu2('upper','suffix',9,2,'grammar','Which sentence correctly introduces a second paragraph?',['Furthermore, the impact of climate change on agriculture has been severe.','Also, climate change is bad for farming too.','Next, let\'s talk about how climate change affects farming.','Moving on, climate change hurts farming a lot.'],'Furthermore, the impact of climate change on agriculture has been severe.',term:2),
  _qu2('upper','prefix',9,2,'vocabulary','What does "infrastructure" mean in a report context?',['The basic systems a society needs to function (roads, power, water)','A type of writing structure','A domain-specific vocabulary term','A formal subheading'],'The basic systems a society needs to function (roads, power, water)',term:2),
  _qu2('upper','suffix',9,2,'vocabulary','What does "analysis" mean?',['a detailed examination to understand components','a personal opinion','a summary of main points','a vocabulary list'],'a detailed examination to understand components',term:2),
  _qu2('upper','suffix',9,2,'grammar','Which is the best concluding sentence for a report?',['In conclusion, the evidence clearly demonstrates that investment in renewable energy is both economically and environmentally necessary.','In conclusion, renewable energy is nice.','So basically we should use renewable energy.','In conclusion, I think renewable energy is a very nice idea.'],'In conclusion, the evidence clearly demonstrates that investment in renewable energy is both economically and environmentally necessary.',term:2),
  _qu2('upper','suffix',9,2,'grammar','Which word signals a concession in a formal report?',['Nevertheless','Furthermore','Moreover','Therefore'],'Nevertheless',term:2),
