  _qu2('upper','homophone',10,1,'vocabulary','What is the difference between "complement" and "compliment"?',['complement = adds to or completes; compliment = praise','compliment = adds to or completes; complement = praise','they are the same word','complement is only a verb'],'complement = adds to or completes; compliment = praise',term:2),
  _qu2('upper','homophone',10,1,'grammar','Choose the correct word: "The sauce perfectly ___ the grilled fish."',['complements','compliments','deserts','counsels'],'complements',term:2),
  _qu2('upper','homophone',10,1,'grammar','Choose the correct word: "She received many ___ on her beautiful artwork."',['compliments','complements','effects','principles'],'compliments',term:2),
  _qu2('upper','homophone',10,1,'vocabulary','What is the difference between "desert" and "dessert"?',['desert = dry land / to abandon; dessert = sweet food after a meal','dessert = dry land; desert = sweet food','they are the same word','desert is only an adjective'],'desert = dry land / to abandon; dessert = sweet food after a meal',term:2),
  _qu2('upper','homophone',10,1,'grammar','Choose the correct word: "The Sahara ___ covers much of North Africa."',['desert','dessert','council','counsel'],'desert',term:2),
  _qu2('upper','homophone',10,1,'grammar','Choose the correct word: "We had chocolate cake for ___."',['dessert','desert','principal','principle'],'dessert',term:2),
  _qu2('upper','homophone',10,1,'vocabulary','What is the difference between "eminent" and "imminent"?',['eminent = famous/respected; imminent = about to happen very soon','imminent = famous/respected; eminent = about to happen','they are the same word','eminent is always a noun'],'eminent = famous/respected; imminent = about to happen very soon',term:2),
