  _qu2('upper','homophone',10,2,'vocabulary','What is the difference between "accept" and "except"?',['accept = to receive or agree to; except = not including / but for','except = to receive; accept = not including','they mean the same thing','accept is always a noun'],'accept = to receive or agree to; except = not including / but for',term:2),
